INSERT INTO `extra_series_events` VALUES
(1,'bgamma',1,'葉層構造に関する代数的トポロジー集会（BGamma）','2003-09-29','2003-10-02','中央大学 後楽園キャンパス・6号館（各日教室変更）','葉層構造に関する代数的トポロジーの主たる結果を概観し、今後の発展を展望。特別講義：Étienne Ghys『Property T d\'après Gromov』。','EwM/79/EwM79.pdf'),
(2,'bgamma',2,'BGamma School','2013-09-17','2013-09-19','中央大学 後楽園キャンパス・5号館1階','BGamma のホモトピー論（h-原理等）の概観と最近の進展。入門講義（Vogt/Meigniez/Asuke）、発展講義、Exercise Class、Wine Party。',NULL),
(3,'bgamma',3,'Seminar on Geometry, Dynamics and Foliations at Chuo University','2013-09-21','2013-09-25','Chuo University・Building No.6・Room 61225 (12th Floor)','幾何・力学系・葉層構造に関するセミナー。Julio Rebelo の3講義と招待講演（Kleptsyn, Cieliebak, Martinez Torres）。',NULL),
(4,'bgamma',4,'BGamma School III — Mather–Thurston 理論とその周辺','2018-03-12','2018-03-14','中央大学 後楽園キャンパス・5号館3階 5334号室','BGamma と葉層構造に関連する最新動向を扱うスクール。Vogt/Meigniez/Nariman/森田による講義。16:15頃よりWine Party。',NULL),
(5,'bgamma',5,'BΓ School IV — Homotopy Theory of Foliations','2023-09-04','2023-09-07','中央大学 後楽園キャンパス・5号館1階 5134号室','葉層構造のホモトピー論に関するスクール。招待講演・ショートコミュニケーション・Banquetあり。',NULL),
(6,'morita',NULL,'森田茂之氏による特別講義',NULL,NULL,NULL,'微分トポロジーの研究と展望等について、森田茂之氏に自由に講演していただきます。',NULL),
(7,'meigniez',NULL,'Gaël Meigniez 教授によるミニコース',NULL,NULL,'中央大学理工学部後楽園キャンパス','\n    20世紀後半を代表する幾何学者・トポロジスト W. Thurston の幾多の仕事の中でも飛びぬけて難解とされる余次元１葉層構造のh-原理（ホモトピー原理）について, 21世紀に入ってから, その単純化と, 4次元以上における飛躍的な進展が Gaël Meigniez 教授（フランス・南ブルターニュ大学）によりなされつつあります.\n    特に4次元以上では, 閉多様体上の任意の横断的向き付け可能な滑らかな余次元1葉層は, 接束の超平面場としてのホモトピー類を変更することなく, コンパクト葉を破壊し, 更に極小葉層（総ての葉が稠密）にまで変形できることを主張しています. 結果として, Novikov の定理（Reeb成分, 特にコンパクト葉の存在）が4次元以上では成立しないことが従います.\n\n    この度 Meigniez 教授は, 中央大学国際交流センター外国人研究者受け入れ制度により本学客員教授としてしばらく後楽園キャンパスに滞在されます. この機会にミニコース（4回連続講演）を企画し, Meigniez 教授ご本人にこの理論を解説していただきます.\n  ',NULL);
